      if (!/^\d{7,8}[-]{0,1}[0-9K]$/i.test(value)) {
        return false;
      }
      value = value.replace(/\-/g, "");
      while (value.length < 9) {
        value = "0" + value;
      }
      var sum = 0,
        weight = [3, 2, 7, 6, 5, 4, 3, 2];
      for (var i = 0; i < 8; i++) {
        sum += parseInt(value.charAt(i), 10) * weight[i];
      }
      sum = 11 - (sum % 11);
      if (sum === 11) {
        sum = 0;
      } else if (sum === 10) {
        sum = "K";
      }
      return sum + "" === value.charAt(8).toUpperCase();
