(function ($) {
  $.fn.serializeFormToObject = function () {
    var $form = $(this);
    var list = {};
    if (!$form.is("form")) {
      $form = $form.find("form");
    }
    $form.each(function (i) {
      var $subForm = $(this);
      $.each($subForm.serializeArray(), function (i, field) {
        if (
          typeof field.value === "string" &&
          (field.value.toLowerCase() === "true" ||
            field.value.toLowerCase() === "yes")
        ) {
          list[field.name] = true;
        } else if (
          typeof field.value === "string" &&
          (field.value.toLowerCase() === "false" ||
            field.value.toLowerCase() === "no")
        ) {
          list[field.name] = false;
        } else {
          list[field.name] = field.value;
        }
        list[field.name] = field.value;
      });
    });
    return list;
  };
})(jQuery);

